# Category: sns_topic_open_subscription

import boto3
import json
from typing import Dict, Any

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    try:
        # Initialize SNS client
        sns_client = boto3.client('sns')
        
        # Extract message and topic ARN from event
        message = event.get('message')
        topic_arn = event.get('topic_arn')
        
        # Validate inputs
        if not message or not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps('Message and topic_arn are required')
            }
        
        # Validate topic ARN format (basic validation)
        if not topic_arn.startswith('arn:aws:sns:'):
            return {
                'statusCode': 400,
                'body': json.dumps('Invalid topic ARN format')
            }
        
        # Publish message to SNS topic
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps(message) if isinstance(message, dict) else str(message),
            Subject=event.get('subject', 'Notification')
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'message_id': response.get('MessageId')
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error publishing message: {str(e)}')
        }